import { Component, OnInit } from '@angular/core';
import { CommonModule } from '@angular/common';
import { Router } from '@angular/router';
import { AuthService } from '../../services/auth.service';

@Component({
  selector: 'app-dashboard',
  standalone: true,
  imports: [CommonModule],
  templateUrl: './dashboard.component.html',
  styleUrls: ['./dashboard.component.css']
})
export class DashboardComponent implements OnInit {
  userEmail: string = '';

  constructor(
    private authService: AuthService,
    private router: Router
  ) {}

  ngOnInit(): void {
    // Get user email from localStorage or from a user service
    // For now, we'll just display a welcome message
    const token = this.authService.getToken();
    if (!token) {
      this.router.navigate(['/login']);
    }
  }

  logout(): void {
    this.authService.logout();
    this.router.navigate(['/login']);
  }
}
<div class="dashboard-container">
  <nav class="navbar">
    <div class="navbar-content">
      <h1 class="navbar-title">Dashboard</h1>
      <button (click)="logout()" class="btn btn-logout">Logout</button>
    </div>
  </nav>

  <div class="dashboard-content">
    <div class="welcome-card">
      <h2>Welcome!</h2>
      <p>You have successfully logged in to the application.</p>
      <p>This is your dashboard where you can manage your account and perform various actions.</p>

      <div class="dashboard-grid">
        <div class="dashboard-item">
          <h3>Profile</h3>
          <p>View and manage your profile information</p>
          <button class="btn btn-secondary">View Profile</button>
        </div>

        <div class="dashboard-item">
          <h3>Settings</h3>
          <p>Configure your application settings</p>
          <button class="btn btn-secondary">Go to Settings</button>
        </div>

        <div class="dashboard-item">
          <h3>Activity</h3>
          <p>View your recent activity and logs</p>
          <button class="btn btn-secondary">View Activity</button>
        </div>

        <div class="dashboard-item">
          <h3>Help</h3>
          <p>Get help and support</p>
          <button class="btn btn-secondary">Get Help</button>
        </div>
      </div>
    </div>
  </div>
</div>
